//! Signature compression and public key serialization.

use crate::{N, Q};

/// Number of bits per coefficient for public key serialization.
const BITS_PER_COEF: usize = 14;

/// Compress a polynomial to bytes using sign + low 7 bits + unary high bits encoding.
///
/// Returns None if the encoding exceeds `slen` bytes.
pub fn compress(v: &[i32], slen: usize) -> Option<Vec<u8>> {
    let mut bits = Vec::with_capacity(8 * slen);

    for &coef in v {
        // Sign bit
        bits.push(coef < 0);

        // Low 7 bits (binary)
        let abs_coef = coef.unsigned_abs();
        for i in (0..7).rev() {
            bits.push((abs_coef >> i) & 1 == 1);
        }

        // High bits (unary: zeros followed by one)
        let high = abs_coef >> 7;
        for _ in 0..high {
            bits.push(false);
        }
        bits.push(true);
    }

    if bits.len() > 8 * slen {
        return None;
    }

    // Pad to slen bytes
    bits.resize(8 * slen, false);

    // Convert to bytes
    let bytes: Vec<u8> = (0..slen)
        .map(|i| {
            let mut byte = 0u8;
            for j in 0..8 {
                if bits[8 * i + j] {
                    byte |= 1 << (7 - j);
                }
            }
            byte
        })
        .collect();

    Some(bytes)
}

/// Decompress bytes to polynomial.
///
/// Returns None if the encoding is invalid.
pub fn decompress(x: &[u8], n: usize) -> Option<Vec<i32>> {
    // Convert bytes to bits
    let mut bits: Vec<bool> = Vec::with_capacity(8 * x.len());
    for &byte in x {
        for i in (0..8).rev() {
            bits.push((byte >> i) & 1 == 1);
        }
    }

    // Remove trailing zeros
    while bits.last() == Some(&false) {
        bits.pop();
    }

    let mut v = Vec::with_capacity(n);
    let mut pos = 0;

    while pos < bits.len() && v.len() < n {
        // Check bounds
        if pos + 8 > bits.len() {
            return None;
        }

        // Sign
        let sign = if bits[pos] { -1 } else { 1 };
        pos += 1;

        // Low 7 bits
        let mut low = 0i32;
        for i in 0..7 {
            if bits[pos + i] {
                low |= 1 << (6 - i);
            }
        }
        pos += 7;

        // High bits (unary)
        let mut high = 0i32;
        while pos < bits.len() && !bits[pos] {
            high += 1;
            pos += 1;
        }

///
/// # Returns
///
/// A tuple of (secret key, verifying key).
pub fn keygen_with_rng<F: FnMut(usize) -> Vec<u8>>(
    random_bytes: &mut F,
) -> (SecretKey, VerifyingKey) {
    // Generate NTRU polynomials
    let (f, g, capital_f, capital_g) = ntru_gen(random_bytes);

    // Compute public key h = g/f mod (x^n + 1, q)
    let f_vec: Vec<i32> = f.iter().copied().collect();
    let g_vec: Vec<i32> = g.iter().copied().collect();
    let h_vec = div_zq(&g_vec, &f_vec).expect("f should be invertible");
    let mut h = [0i32; N];
    h.copy_from_slice(&h_vec);

    // Compute basis B0 = [[g, -f], [G, -F]] in coefficient representation
    // Note: Use regular negation, NOT modular negation (neg_zq), for the Gram matrix
    let neg_f: Vec<f64> = f_vec.iter().map(|&x| -(x as f64)).collect();
    let neg_f_cap: Vec<f64> = capital_f.iter().map(|&x| -(x as f64)).collect();

    // B0 in coefficient representation (f64 for Gram computation)
    let b0: [[Vec<f64>; 2]; 2] = [
        [g_vec.iter().map(|&x| x as f64).collect(), neg_f],
        [capital_g.iter().map(|&x| x as f64).collect(), neg_f_cap],
    ];

    // Convert B0 to FFT representation (for use in signing)
    let b0_fft = [
        [fft(&b0[0][0]), fft(&b0[0][1])],
        [fft(&b0[1][0]), fft(&b0[1][1])],
    ];

    // Compute Gram matrix G0 = B0 * B0^* in coefficient representation
    // (matching Python's approach: gram() in coef domain, then FFT)
    let g0 = gram(&b0);
    let g0_fft = [
        [fft(&g0[0][0]), fft(&g0[0][1])],
        [fft(&g0[1][0]), fft(&g0[1][1])],
    ];

    // Build ffLDL tree
    let mut tree = ffldl_fft(&g0_fft);
    normalize_tree(&mut tree, SIGMA);

    let sk = SecretKey {
        f,
        g,
        capital_f,
        capital_g,
        b0_fft,
        tree,
    };

    let vk = VerifyingKey { h };

    (sk, vk)
}

